var authGuard = () => {
  const auth = inject2(AuthService);
  const router = inject2(Router);
  if (auth.isLoggedIn()) {
    return true;
  }
  router.navigate(["/login"]);
  return false;
};

// src/app/guards/admin-guard.ts
