// src/app/interceptors/auth-interceptor.ts
var authInterceptor = (req, next) => {
  const auth = inject2(AuthService);
  const token = auth.getToken();
  if (!token) {
    return next(req);
  }
  const cloned = req.clone({ setHeaders: { "x-auth-token": token } });
  return next(cloned);
};

// src/app/interceptors/error-interceptor.ts
var REQUEST_TIMEOUT_MS = 2e4;
var errorInterceptor = (req, next) => {
  const router = inject2(Router);
  const auth = inject2(AuthService);
  const feedback = inject2(AppFeedbackService);
  return next(req).pipe(timeout(REQUEST_TIMEOUT_MS), catchError((error) => {
    if (error instanceof TimeoutError) {
      feedback.showError("This request timed out. Please try again.");
      return throwError(() => error);
    }
    if (error instanceof HttpErrorResponse) {
      const backendMessage = normalizeServerMessage(error);
      if (error.status === 0) {
        feedback.showError("Unable to reach the server. Check your connection and try again.");
        return throwError(() => error);
      }
      if (error.status === 401) {
        auth.clearToken();
        router.navigate(["/login"]);
        feedback.showError(backendMessage || "Your session has expired. Please log in again.");
        return throwError(() => error);
      }
      if (error.status === 403) {
        feedback.showError(backendMessage || "You do not have permission to access this resource.");
        return throwError(() => error);
      }
      if (error.status === 404) {
        feedback.showError(backendMessage || "We could not find what you requested.");
        return throwError(() => error);
      }
      if (error.status >= 500) {
        feedback.showError(backendMessage || "Server error. Please try again shortly.");
        return throwError(() => error);
      }
      if (backendMessage) {
        feedback.showError(backendMessage);
      }
    }
    return throwError(() => error);
  }));
};
function normalizeServerMessage(error) {
  if (!error)
    return "";
  const raw = (typeof error.error === "string" ? error.error : "") || error.error?.msg || error.error?.message || error.error?.error || "";
  return typeof raw === "string" ? raw.trim() : "";
}

// src/app/app.config.ts
var appConfig = {
  providers: [
    provideBrowserGlobalErrorListeners(),
    provideZoneChangeDetection({ eventCoalescing: true }),
    provideRouter(routes),
    provideHttpClient(withInterceptors([authInterceptor, errorInterceptor]))
  ]
};

